logging.basicConfig(level=logging.WARNING)

def _req(k):
    v = os.getenv(k, "")
    if not v: print(f"[警告] 環境變數 {k} 未設定")
    return v

SMTP_HOST     = _req("SMTP_HOST")
SMTP_PORT     = int(os.getenv("SMTP_PORT", "465"))
SMTP_E_USER   = _req("SMTP_USER_EAST")
SMTP_E_PASS   = _req("SMTP_PASSWORD_EAST")
SMTP_W_USER   = _req("SMTP_USER_WEST")
SMTP_W_PASS   = _req("SMTP_PASSWORD_WEST")
MANAGER_EMAIL = _req("MANAGER_EMAIL")
TRACKER_URL   = os.getenv("TRACKER_URL", "https://klub-frastea-tracker.zeabur.app")

# ── 發信速率控制 ──────────────────────────────────────────────
SEND_INTERVAL_MIN = 20      # 每封最短間隔秒
SEND_INTERVAL_MAX = 30      # 每封最長間隔秒
SEND_JITTER       = 5       # 隨機抖動秒
HOURLY_LIMIT      = 120     # 每小時上限
BATCH_SIZE        = 30      # 每批次發送數
BATCH_PAUSE       = 300     # 批次間暫停秒（5分鐘）
SEND_HOUR_START   = 12      # UTC 12:00 = 台灣 20:00
SEND_HOUR_END     = 15      # UTC 15:00 = 台灣 23:00

_sent_this_hour = 0
_hour_start_time = None

def check_send_window():
    """確認是否在台灣 20:00-23:00 發信時段（UTC 12:00-15:00）"""
    now_utc = datetime.datetime.utcnow()
    if now_utc.weekday() >= 5:  # 週六=5, 週日=6
        print(f"  [暫停] 週末不發信")
        return False
    if not (SEND_HOUR_START <= now_utc.hour < SEND_HOUR_END):
        tw_hour = (now_utc.hour + 8) % 24
        print(f"  [暫停] 現在台灣時間 {tw_hour:02d}:{now_utc.minute:02d}，發信時段為 20:00-23:00")
        return False
    return True

def rate_limit_wait(sent_count):
    """控制發信間隔和每小時上限"""
    global _sent_this_hour, _hour_start_time
    now = time.time()
    
    # 初始化小時計時器
    if _hour_start_time is None:
        _hour_start_time = now
        _sent_this_hour = 0
    
    # 超過1小時，重置計數器
    if now - _hour_start_time >= 3600:
        _hour_start_time = now
        _sent_this_hour = 0
    
    # 達到每小時上限，等到下一小時
    if _sent_this_hour >= HOURLY_LIMIT:
        wait = 3600 - (now - _hour_start_time)
        print(f"  [速率] 已達每小時上限 {HOURLY_LIMIT} 封，等待 {wait:.0f} 秒")
        time.sleep(wait + 5)
        _hour_start_time = time.time()
        _sent_this_hour = 0
    
    # 批次間暫停
    if sent_count > 0 and sent_count % BATCH_SIZE == 0:
        print(f"  [批次] 已發 {sent_count} 封，暫停 {BATCH_PAUSE} 秒")
        time.sleep(BATCH_PAUSE)
    
    # 每封間隔
    interval = random.uniform(SEND_INTERVAL_MIN, SEND_INTERVAL_MAX)
    jitter = random.uniform(-SEND_JITTER, SEND_JITTER)
    total_wait = max(10, interval + jitter)
    time.sleep(total_wait)
    
    _sent_this_hour += 1

ACCOUNTS = {
    "East":  {"user": SMTP_E_USER, "pass": SMTP_E_PASS},
    "West":  {"user": SMTP_W_USER, "pass": SMTP_W_PASS},
}

DB_PATH = "us_v25.db"
TODAY   = datetime.date.today().isoformat()

IMG_M = "data:image/png;base64,"
IMG_R = "data:image/png;base64,"

# ── DB ──────────────────────────────────────────────────────
def init_db():
    con = sqlite3.connect(DB_PATH)
    con.execute("""CREATE TABLE IF NOT EXISTS sent_log (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        email TEXT, company TEXT, tier TEXT, region TEXT,
        subject TEXT, status TEXT, sent_at TEXT, tracking_id TEXT,
        open_count INTEGER DEFAULT 0)""")
    con.commit(); con.close()

def already_sent(email, company):
    con = sqlite3.connect(DB_PATH)
    row = con.execute(
        "SELECT 1 FROM sent_log WHERE email=? AND company=? AND sent_at LIKE ?",
        (email, company, TODAY+"%")).fetchone()
    con.close()
    return row is not None

def log_sent(email, company, tier, region, subject, status, tid):
    con = sqlite3.connect(DB_PATH)
    con.execute("INSERT INTO sent_log (email,company,tier,region,subject,status,sent_at,tracking_id) VALUES (?,?,?,?,?,?,?,?)",
        (email, company, tier, region, subject, status, datetime.datetime.now().isoformat(), tid))
    con.commit(); con.close()

# ── SMTP ────────────────────────────────────────────────────
def smtp_send(to, subject, html, region="East"):
    acct = ACCOUNTS.get(region, ACCOUNTS["East"])
    msg = MIMEMultipart("alternative")
    msg["Subject"] = subject
    msg["From"]    = f"KLUB x Frastea <{acct['user']}>"
    msg["To"]      = to
    msg.attach(MIMEText(html, "html", "utf-8"))
    try:
        if SMTP_PORT == 465:
            s = smtplib.SMTP_SSL(SMTP_HOST, SMTP_PORT, timeout=20)
        else:
            s = smtplib.SMTP(SMTP_HOST, SMTP_PORT, timeout=20)
            s.ehlo(); s.starttls()
        s.ehlo()
        s.login(acct["user"], acct["pass"])
        s.sendmail(acct["user"], [to], msg.as_string())
        s.quit()
        print(f"     OK ({acct['user']} -> {to})")
        return True
    except Exception as e:
        print(f"     FAIL [{region}]: {e}")
        return False

# ── Tracking ────────────────────────────────────────────────
def pixel_html(tid, email, tier):
    url = f"{TRACKER_URL}/track/{tid}?email={email}&day=Day1&tier={tier}"
    return f'<img src="{url}" width="1" height="1" style="display:none" alt="">'

def approve_url(tid, target):
    return f"{TRACKER_URL}/approve/{tid}?approver={MANAGER_EMAIL}&target={target}"

# ── Product detection ────────────────────────────────────────
def detect_product(industry):
    ind = industry.lower()
    if any(k in ind for k in ["f&b","beverage","cafe","restaurant","bubble tea","tea","food","drink"]):
        return "raw"
    if any(k in ind for k in ["fitness","gym","wellness","spa","health"]):
        return "machinery"
    return "both"

